'use client';

import { useState } from 'react';

type Tab = 'ranking' | 'logros' | 'quiz' | 'kiosco' | 'perdidos' | 'spotify';

const LEADERBOARD = [
    { rank: 1, name: 'María García', xp: 2450, level: 'Fallera Legendaria', badge: '👑' },
    { rank: 2, name: 'Pablo Martínez', xp: 2280, level: 'Fallero Veterano', badge: '⭐' },
    { rank: 3, name: 'Lucía Fernández', xp: 2100, level: 'Fallera Veterana', badge: '🌟' },
    { rank: 4, name: 'Carlos Ruiz', xp: 1890, level: 'Fallero Experto', badge: '💪' },
    { rank: 5, name: 'Ana Torres', xp: 1750, level: 'Fallera Experta', badge: '🔥' },
    { rank: 6, name: 'Andrés López', xp: 1620, level: 'Fallero Avanzado', badge: '📈' },
    { rank: 7, name: 'Eva Moreno', xp: 1580, level: 'Fallera Avanzada', badge: '✨' },
    { rank: 8, name: 'Miguel Sanz', xp: 1400, level: 'Fallero Intermedio', badge: '🎯' },
];

const ACHIEVEMENTS = [
    { icon: '🏆', name: 'Superviviente Ofrenda', desc: 'Completar la ofrenda sin sentarse', rarity: 'Épico', unlocked: true },
    { icon: '🍳', name: 'Master Paellero', desc: 'Cocinar más de 5 paellas para la falla', rarity: 'Raro', unlocked: true },
    { icon: '🎤', name: 'Estrella del Playback', desc: 'Participar en 3 playbacks consecutivos', rarity: 'Épico', unlocked: true },
    { icon: '🌙', name: 'Noctámbulo', desc: 'Ser el último en cerrar la barra 10 veces', rarity: 'Legendario', unlocked: false },
    { icon: '🍺', name: 'Rey de la Barra', desc: 'Completar 20 turnos de barra', rarity: 'Raro', unlocked: true },
    { icon: '💪', name: 'Madrugador', desc: 'Llegar el primero a 5 despertàs', rarity: 'Común', unlocked: false },
    { icon: '📸', name: 'Influencer Fallero', desc: 'Subir 100 fotos a la galería', rarity: 'Raro', unlocked: false },
    { icon: '🎆', name: 'Pirotécnico de Honor', desc: 'Asistir a todas las mascletàs del año', rarity: 'Legendario', unlocked: false },
    { icon: '🗳️', name: 'Demócrata', desc: 'Votar en todas las encuestas del año', rarity: 'Común', unlocked: true },
];

const QUIZ_QUESTIONS = [
    {
        question: '¿En qué año se celebró la primera Plantà moderna en Valencia?',
        options: ['1901', '1929', '1940', '1895'],
        correct: 0,
    },
    {
        question: '¿Cómo se llama el acto de quemar la falla?',
        options: ['Plantà', 'Cremà', 'Despertà', 'Mascletà'],
        correct: 1,
    },
    {
        question: '¿Qué día es la Ofrenda de Flores a la Virgen de los Desamparados?',
        options: ['15 de Marzo', '17-18 de Marzo', '19 de Marzo', '16 de Marzo'],
        correct: 1,
    },
];

const LOST_ITEMS = [
    { id: 1, item: 'Chaqueta negra de hombre', lugar: 'Barra del casal', fecha: '09/02/2026', estado: 'Sin reclamar', emoji: '🧥' },
    { id: 2, item: 'iPhone 15 con funda roja', lugar: 'Mesa 3 — Cena', fecha: '08/02/2026', estado: 'Reclamado', emoji: '📱' },
    { id: 3, item: 'Gafas de sol Ray-Ban', lugar: 'Terraza', fecha: '07/02/2026', estado: 'Sin reclamar', emoji: '🕶️' },
    { id: 4, item: 'Llaves con llavero de Valencia CF', lugar: 'Entrada casal', fecha: '05/02/2026', estado: 'Sin reclamar', emoji: '🔑' },
    { id: 5, item: 'Pañuelo de fallera infantil', lugar: 'Vestuario', fecha: '03/02/2026', estado: 'Reclamado', emoji: '🧣' },
];

const SPOTIFY_PLAYLIST = [
    { song: 'Pio Pio — Barra Libre', votes: 45, emoji: '🎵' },
    { song: 'Paquito el Chocolatero', votes: 38, emoji: '🍫' },
    { song: 'Vent de Llevant — Obrint Pas', votes: 32, emoji: '🌊' },
    { song: 'Bad Bunny — Tití me preguntó', votes: 28, emoji: '🐰' },
    { song: 'Rosalía — Despechá', votes: 25, emoji: '🌹' },
    { song: 'Valencia — Himne Regional', votes: 18, emoji: '🏛️' },
    { song: 'Ai, ¡Eixina falles!', votes: 15, emoji: '🔥' },
];

export default function FunPage() {
    const [activeTab, setActiveTab] = useState<Tab>('ranking');
    const [quizIndex, setQuizIndex] = useState(0);
    const [quizAnswer, setQuizAnswer] = useState<number | null>(null);
    const [quizScore, setQuizScore] = useState(0);

    const tabs: { key: Tab; label: string; icon: string }[] = [
        { key: 'ranking', label: 'Ranking', icon: '🏆' },
        { key: 'logros', label: 'Logros', icon: '🎖️' },
        { key: 'quiz', label: 'Quiz', icon: '❓' },
        { key: 'kiosco', label: 'Kiosco', icon: '📺' },
        { key: 'perdidos', label: 'Perdidos', icon: '🔍' },
        { key: 'spotify', label: 'Spotify', icon: '🎧' },
    ];

    const handleQuizAnswer = (idx: number) => {
        setQuizAnswer(idx);
        if (idx === QUIZ_QUESTIONS[quizIndex].correct) {
            setQuizScore((s) => s + 1);
        }
    };

    const nextQuestion = () => {
        if (quizIndex < QUIZ_QUESTIONS.length - 1) {
            setQuizIndex((i) => i + 1);
            setQuizAnswer(null);
        }
    };

    return (
        <div>
            <div className="page-header">
                <h1 className="page-title">🎮 Fun Zone</h1>
                <p className="page-subtitle">Gamificación, entretenimiento y comunidad</p>
            </div>

            <div className="tabs">
                {tabs.map((t) => (
                    <button key={t.key} className={`tab ${activeTab === t.key ? 'active' : ''}`} onClick={() => setActiveTab(t.key)}>
                        {t.icon} {t.label}
                    </button>
                ))}
            </div>

            {/* RANKING */}
            {activeTab === 'ranking' && (
                <div className="animate-fade-in">
                    <div className="grid-2">
                        <div className="card" style={{ padding: 0 }}>
                            <div style={{ padding: '20px 20px 8px' }}>
                                <h3>🏆 Ranking Fallero del Año 2026</h3>
                            </div>
                            {LEADERBOARD.map((l) => (
                                <div key={l.rank} className="leaderboard-item">
                                    <div className={`leaderboard-rank ${l.rank === 1 ? 'gold' : l.rank === 2 ? 'silver' : l.rank === 3 ? 'bronze' : ''}`}>
                                        {l.rank <= 3 ? ['🥇', '🥈', '🥉'][l.rank - 1] : `#${l.rank}`}
                                    </div>
                                    <div className="chat-avatar" style={{ background: `hsl(${l.rank * 45}, 60%, 50%)` }}>
                                        {l.badge}
                                    </div>
                                    <div className="leaderboard-info">
                                        <div className="leaderboard-name">{l.name}</div>
                                        <div className="leaderboard-xp">{l.level}</div>
                                    </div>
                                    <div className="leaderboard-score">{l.xp} XP</div>
                                </div>
                            ))}
                        </div>
                        <div>
                            <div className="card" style={{ marginBottom: 20 }}>
                                <h4 style={{ marginBottom: 16 }}>📊 Cómo Ganar XP</h4>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                                    {[
                                        { action: 'Asistir a un acto', xp: '+50 XP' },
                                        { action: 'Turno de barra', xp: '+100 XP' },
                                        { action: 'Participar en playback', xp: '+150 XP' },
                                        { action: 'Ofrenda completa', xp: '+200 XP' },
                                        { action: 'Traer nuevo fallero', xp: '+300 XP' },
                                    ].map((r, i) => (
                                        <div key={i} style={{
                                            display: 'flex',
                                            justifyContent: 'space-between',
                                            padding: '8px 0',
                                            borderBottom: '1px solid var(--border-subtle)',
                                            fontSize: 14,
                                        }}>
                                            <span>{r.action}</span>
                                            <span style={{ color: 'var(--accent-green)', fontWeight: 600 }}>{r.xp}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            <div className="stat-card" style={{ textAlign: 'center' }}>
                                <div style={{ fontSize: 40, marginBottom: 8 }}>🏅</div>
                                <div className="stat-value" style={{ fontSize: 20 }}>Temporada 2025-2026</div>
                                <div className="stat-label">Quedan 33 días para el cierre</div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* LOGROS */}
            {activeTab === 'logros' && (
                <div className="animate-fade-in">
                    <div className="grid-3">
                        {ACHIEVEMENTS.map((a, i) => (
                            <div key={i} className="card-glass" style={{
                                textAlign: 'center',
                                opacity: a.unlocked ? 1 : 0.4,
                                filter: a.unlocked ? 'none' : 'grayscale(1)',
                                transition: 'all var(--transition-normal)',
                            }}>
                                <div style={{ fontSize: 48, marginBottom: 8 }}>{a.icon}</div>
                                <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 4 }}>{a.name}</div>
                                <div style={{ fontSize: 12, color: 'var(--text-secondary)', marginBottom: 8 }}>{a.desc}</div>
                                <span className={`badge ${a.rarity === 'Legendario' ? 'warning' :
                                        a.rarity === 'Épico' ? 'purple' :
                                            a.rarity === 'Raro' ? 'info' : 'success'
                                    }`}>
                                    {a.rarity}
                                </span>
                                {a.unlocked && <div style={{ fontSize: 10, color: 'var(--accent-green)', marginTop: 8 }}>✓ Desbloqueado</div>}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* QUIZ */}
            {activeTab === 'quiz' && (
                <div className="animate-fade-in" style={{ maxWidth: 600, margin: '0 auto' }}>
                    <div className="card">
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
                            <span className="badge info">Pregunta {quizIndex + 1} de {QUIZ_QUESTIONS.length}</span>
                            <span className="badge success">Puntuación: {quizScore}/{QUIZ_QUESTIONS.length}</span>
                        </div>
                        <h3 style={{ marginBottom: 24, fontSize: 18, lineHeight: 1.5 }}>
                            {QUIZ_QUESTIONS[quizIndex].question}
                        </h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                            {QUIZ_QUESTIONS[quizIndex].options.map((opt, i) => (
                                <button
                                    key={i}
                                    className="poll-option"
                                    onClick={() => quizAnswer === null && handleQuizAnswer(i)}
                                    style={{
                                        borderColor: quizAnswer !== null
                                            ? i === QUIZ_QUESTIONS[quizIndex].correct
                                                ? 'var(--accent-green)'
                                                : i === quizAnswer ? 'var(--accent-red)' : undefined
                                            : undefined,
                                        background: quizAnswer !== null
                                            ? i === QUIZ_QUESTIONS[quizIndex].correct
                                                ? 'rgba(16,185,129,0.1)'
                                                : i === quizAnswer ? 'rgba(239,68,68,0.1)' : undefined
                                            : undefined,
                                        cursor: quizAnswer === null ? 'pointer' : 'default',
                                    }}
                                >
                                    <div className="poll-option-content">
                                        <span>{opt}</span>
                                        {quizAnswer !== null && i === QUIZ_QUESTIONS[quizIndex].correct && <span>✅</span>}
                                        {quizAnswer !== null && i === quizAnswer && i !== QUIZ_QUESTIONS[quizIndex].correct && <span>❌</span>}
                                    </div>
                                </button>
                            ))}
                        </div>
                        {quizAnswer !== null && quizIndex < QUIZ_QUESTIONS.length - 1 && (
                            <div style={{ marginTop: 20, textAlign: 'center' }}>
                                <button className="btn btn-primary" onClick={nextQuestion}>Siguiente Pregunta →</button>
                            </div>
                        )}
                        {quizAnswer !== null && quizIndex === QUIZ_QUESTIONS.length - 1 && (
                            <div style={{ marginTop: 20, textAlign: 'center', padding: 20 }}>
                                <div style={{ fontSize: 40, marginBottom: 8 }}>🎉</div>
                                <div style={{ fontSize: 18, fontWeight: 700 }}>¡Quiz completado!</div>
                                <div style={{ color: 'var(--text-secondary)' }}>Has acertado {quizScore} de {QUIZ_QUESTIONS.length}</div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* KIOSCO */}
            {activeTab === 'kiosco' && (
                <div className="animate-fade-in" style={{ textAlign: 'center' }}>
                    <div className="card" style={{ padding: 48, background: 'linear-gradient(135deg, rgba(59,130,246,0.1), rgba(139,92,246,0.05))' }}>
                        <div style={{ fontSize: 72, marginBottom: 24 }}>📺</div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 32, fontWeight: 800, marginBottom: 12 }}>Modo Kiosco</h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 16, maxWidth: 500, margin: '0 auto 32px' }}>
                            Interfaz simplificada para tablet fija en la entrada del Casal.
                            Muestra información relevante y permite check-in rápido.
                        </p>
                        <div className="stats-grid" style={{ maxWidth: 600, margin: '0 auto 32px' }}>
                            <div className="stat-card">
                                <div className="stat-value" style={{ fontSize: 24 }}>247</div>
                                <div className="stat-label">Falleros</div>
                            </div>
                            <div className="stat-card">
                                <div className="stat-value" style={{ fontSize: 24 }}>14</div>
                                <div className="stat-label">Eventos</div>
                            </div>
                            <div className="stat-card">
                                <div className="stat-value" style={{ fontSize: 24 }}>87</div>
                                <div className="stat-label">Check-ins hoy</div>
                            </div>
                        </div>
                        <button className="btn btn-primary" style={{ padding: '14px 40px', fontSize: 16 }}>
                            🖥️ Activar Modo Kiosco
                        </button>
                    </div>
                </div>
            )}

            {/* OBJETOS PERDIDOS */}
            {activeTab === 'perdidos' && (
                <div className="animate-fade-in">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                        <h3 className="section-title" style={{ margin: 0 }}>🔍 Objetos Perdidos</h3>
                        <button className="btn btn-primary">+ Registrar Objeto</button>
                    </div>
                    <div className="card">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th></th>
                                    <th>Objeto</th>
                                    <th>Encontrado en</th>
                                    <th>Fecha</th>
                                    <th>Estado</th>
                                </tr>
                            </thead>
                            <tbody>
                                {LOST_ITEMS.map((item) => (
                                    <tr key={item.id}>
                                        <td style={{ fontSize: 24 }}>{item.emoji}</td>
                                        <td style={{ fontWeight: 500 }}>{item.item}</td>
                                        <td>{item.lugar}</td>
                                        <td>{item.fecha}</td>
                                        <td>
                                            <span className={`badge ${item.estado === 'Reclamado' ? 'success' : 'warning'}`}>
                                                {item.estado}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* SPOTIFY */}
            {activeTab === 'spotify' && (
                <div className="animate-fade-in" style={{ maxWidth: 600, margin: '0 auto' }}>
                    <div className="card" style={{ marginBottom: 20, background: 'linear-gradient(135deg, rgba(30,215,96,0.1), rgba(30,215,96,0.02))', borderColor: 'rgba(30,215,96,0.2)' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
                            <span style={{ fontSize: 32 }}>🎧</span>
                            <div>
                                <h3>Votación Musical</h3>
                                <p style={{ color: 'var(--text-secondary)', fontSize: 13 }}>Vota la música para la próxima discomóvil</p>
                            </div>
                        </div>
                        <input className="input" placeholder="🔍 Buscar canción o artista..." />
                    </div>
                    <div className="card" style={{ padding: 0 }}>
                        {SPOTIFY_PLAYLIST.map((s, i) => (
                            <div key={i} style={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: 16,
                                padding: '14px 20px',
                                borderBottom: '1px solid var(--border-subtle)',
                                transition: 'background 150ms ease',
                            }}>
                                <span style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-muted)', width: 24 }}>#{i + 1}</span>
                                <span style={{ fontSize: 24 }}>{s.emoji}</span>
                                <div style={{ flex: 1 }}>
                                    <div style={{ fontWeight: 500, fontSize: 14 }}>{s.song}</div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                    <span style={{ fontWeight: 600, color: 'var(--accent-green)' }}>{s.votes}</span>
                                    <button className="btn btn-ghost" style={{ padding: '6px 12px', fontSize: 13 }}>👍</button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}
